import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart";

function MapComponent() {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data);
      } catch (err) {
        console.error("Error fetching buses:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // every 2 minutes
    return () => clearInterval(interval);
  }, []);

  const getColor = (status) => {
    if (status === "normal") return "green";
    if (status === "ghost") return "red";
    if (status === "anomaly") return "orange";
    return "blue";
  };

  return (
    <div style={{ position: "relative", width: "100vw", height: "100vh", overflow: "hidden" }}>
      {/* Toggle Button */}
      <button
        onClick={() => setShowChart(!showChart)}
        style={{
          position: "absolute",
          top: 10,
          left: 10,
          zIndex: 1000,
          padding: "8px 12px",
          backgroundColor: "#fff",
          border: "1px solid #ccc",
          borderRadius: "4px",
          cursor: "pointer",
        }}
      >
        {showChart ? "Hide Bus Trend" : "Show Bus Trend"}
      </button>

      {/* Floating Chart Panel */}
      {showChart && (
        <div
          style={{
            position: "absolute",
            bottom: 10,
            left: 10,
            zIndex: 1000,
            width: "400px",
            height: "300px",
            backgroundColor: "rgba(255, 255, 255, 0.95)",
            padding: "10px",
            borderRadius: "8px",
            boxShadow: "0 0 10px rgba(0,0,0,0.3)",
          }}
        >
          <BusTrendChart data={buses} />
        </div>
      )}

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ width: "100%", height: "100%" }}
        scrollWheelZoom={false} // disables scroll zoom to prevent page scroll
        dragging={true}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="&copy; OpenStreetMap contributors"
        />

        {buses.map((bus) => (
          <CircleMarker
            key={bus.id + bus.timestamp} // ensures unique key
            center={[bus.lat, bus.lon]}
            radius={6}
            color={getColor(bus.status)}
            fillOpacity={1}
          >
            <Popup>
              <div>
                <b>ID:</b> {bus.id} <br />
                <b>Status:</b> {bus.status}
              </div>
            </Popup>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}

export default MapComponent;
